// Expand JSONB keywords array so each keyword becomes its own item
const items = [];
for (const client of $input.all()) {
  const { id, client_name, domain, keywords, country, engine } = client.json;
  const kwList = Array.isArray(keywords) ? keywords : JSON.parse(keywords);
  for (const keyword of kwList) {
    items.push({
      json: { client_id: id, client_name, domain, keyword, country, engine }
    });
  }
}
return items;

// Extract domain rank from DataForSEO response
// Adjust parsing if using a different SERP API
const item = $input.first().json;
const clientDomain = item.domain || '';

let rank = null;

try {
  // DataForSEO response structure
  const results = item.tasks?.[0]?.result?.[0]?.items || [];
  for (const r of results) {
    if (r.type === 'organic' && r.url && r.url.includes(clientDomain)) {
      rank = r.rank_absolute;
      break;
    }
  }
} catch (e) {
  // If parsing fails, rank stays null (not found)
}

/* ValueSERP alternative parsing:
const results = item.organic_results || [];
for (const r of results) {
  if (r.link && r.link.includes(clientDomain)) {
    rank = r.position;
    break;
  }
}
*/

return [{ json: { ...item, rank } }];

// Aggregate results for the summary email
const allItems = $input.all();
const improved = allItems.filter(i => i.json.rank && i.json.rank <= 10).length;
const total = allItems.length;
const date = new Date().toISOString().split('T')[0];

let tableRows = allItems.map(i => {
  const r = i.json;
  return `<tr><td>${r.client_name || ''}</td><td>${r.keyword}</td><td>${r.rank || 'Not found'}</td></tr>`;
}).join('');

const html = `
<h2>RankTracker Daily Report — ${date}</h2>
<p>Checked <strong>${total}</strong> keywords. <strong>${improved}</strong> ranked in the top 10.</p>
<table border="1" cellpadding="6" style="border-collapse:collapse;font-family:sans-serif;font-size:13px">
  <thead><tr><th>Client</th><th>Keyword</th><th>Rank</th></tr></thead>
  <tbody>${tableRows}</tbody>
</table>
`;

return [{ json: { html, total, improved, date } }];
